    @pytest.mark.asyncio
    async def test_audit_event_timestamp_is_utc(
        self, valid_patient, mock_fhir_client, audit_event_recorder
    ):
        """The 'recorded' field in AuditEvent MUST be a valid UTC ISO-8601 timestamp."""
        patient_id = str(uuid.uuid4())
        audit_payload = _build_audit_event(
            action="C", outcome="0", patient_id=patient_id
        )
