class TestPatientCreationMissingMandatoryElements:
    """Server MUST reject Patient creation when mandatory elements are absent."""

    @pytest.mark.asyncio
    @pytest.mark.parametrize(
        "missing_field, payload_override",
        [
            ("family name", {"family": None}),
            ("given name", {"given": None}),
            ("gender", {"gender": None}),
            ("birthDate", {"birth_date": None}),
            (
                "identifier",
                {"identifier_system": None, "identifier_value": None},
            ),
        ],
    )
    async def test_missing_field_returns_422(
        self,
        missing_field,
        payload_override,
        mock_fhir_client,
        audit_event_recorder,
    ):
        """POST /Patient missing a mandatory field MUST return HTTP 422."""
        payload = _valid_patient_payload(**payload_override)
        mock_fhir_client.post(f"{BASE_URL}/Patient").mock(
            return_value=httpx.Response(
                422,
                json={
                    "resourceType": "OperationOutcome",
                    "issue": [
                        {
                            "severity": "error",
                            "code": "required",
                            "diagnostics": f"Missing mandatory element: {missing_field}",
                        }
                    ],
                },
            )
        )

        async with httpx.AsyncClient(base_url=BASE_URL) as client:
            response = await client.post(
                "/Patient", json=payload, headers=_auth_headers()
            )

        assert response.status_code == 422, (
            f"Expected 422 for missing '{missing_field}', got {response.status_code}"
        )
        body = response.json()
        assert body["resourceType"] == "OperationOutcome"
        issues = body.get("issue", [])
        assert issues, "OperationOutcome must contain at least one issue"
        assert all(i["severity"] == "error" for i in issues)

    @pytest.mark.asyncio
    async def test_empty_body_returns_400(
        self, mock_fhir_client, audit_event_recorder
    ):
