        audit_payload = _build_audit_event(
            action="C",
            outcome="8",   # FHIR: 0=success, 4=minor failure, 8=serious failure
            patient_id=None,
            agent_token=CLINICIAN_TOKEN,
        )
        audit_event_recorder.append(audit_payload)

        event = _latest_audit_event(audit_event_recorder)
        _assert_audit_event_shape(event, action="C", outcome="8")


