class TestAuditEventEndToEnd:
    """End-to-end validation of AuditEvent content and persistence."""

    @pytest.mark.asyncio
    async def test_audit_event_is_persisted_to_fhir_store(
        self, valid_patient, mock_fhir_client
    ):
        """The AuditEvent POST to the FHIR store MUST be observed end-to-end."""
        patient_id = str(uuid.uuid4())
        audit_id = str(uuid.uuid4())

        mock_fhir_client.post(f"{BASE_URL}/Patient").mock(
            return_value=httpx.Response(
                201, json={**valid_patient, "id": patient_id}
            )
        )
        audit_event_post = mock_fhir_client.post(f"{BASE_URL}/AuditEvent").mock(
            return_value=httpx.Response(
                201, json={"resourceType": "AuditEvent", "id": audit_id}
            )
        )

        async with httpx.AsyncClient(base_url=BASE_URL) as client:
            await client.post(
                "/Patient", json=valid_patient, headers=_auth_headers()
            )
            audit_payload = _build_audit_event(
                action="C", outcome="0", patient_id=patient_id
            )
            audit_response = await client.post(
                "/AuditEvent", json=audit_payload, headers=_auth_headers()
            )

        assert audit_event_post.called, "AuditEvent was not persisted to FHIR store"
        assert audit_response.status_code == 201

    @pytest.mark.asyncio
    async def test_audit_event_entity_references_created_patient(
        self, valid_patient, mock_fhir_client, audit_event_recorder
    ):
        """The AuditEvent entity.what MUST reference the newly created Patient."""
        patient_id = str(uuid.uuid4())

        audit_payload = _build_audit_event(
            action="C",
            outcome="0",
            patient_id=patient_id,
        )
        audit_event_recorder.append(audit_payload)

        event = _latest_audit_event(audit_event_recorder)
        entities = event.get("entity", [])
        assert entities, "AuditEvent must have at least one entity"
        references = [
            e.get("what", {}).get("reference", "") for e in entities
        ]
        assert any(patient_id in ref for ref in references), (
            f"No entity references Patient/{patient_id}. "
            f"Found references: {references}"
        )

    @pytest.mark.asyncio
    async def test_audit_event_type_coding_is_correct(
        self, valid_patient, mock_fhir_client, audit_event_recorder
    ):
        """AuditEvent type MUST use the DICOM audit event type code (rest-operation)."""
        patient_id = str(uuid.uuid4())
        audit_payload = _build_audit_event(
            action="C", outcome="0", patient_id=patient_id
        )
        audit_event_recorder.append(audit_payload)

        event = _latest_audit_event(audit_event_recorder)
        event_type = event.get("type", {})
        assert event_type.get("system") is not None, "AuditEvent.type.system is missing"
        assert event_type.get("code") is not None, "AuditEvent.type.code is missing"

    @pytest.mark.asyncio
    async def test_audit_event_subtype_reflects_fhir_operation(
        self, valid_patient, mock_fhir_client, audit_event_recorder
    ):
        """AuditEvent subtype MUST reflect the FHIR 'create' interaction."""
        patient_id = str(uuid.uuid4())
        audit_payload = _build_audit_event(
            action="C", outcome="0", patient_id=patient_id
        )
        audit_event_recorder.append(audit_payload)

        event = _latest_audit_event(audit_event_recorder)
        subtypes = event.get("subtype", [])
        assert subtypes, "AuditEvent.subtype must be populated"
        codes = [s.get("code") for s in subtypes]
        assert "create" in codes, f"Expected 'create' in subtype codes, got {codes}"

    @pytest.mark.asyncio
    async def test_one_audit_event_per_operation(
        self, valid_patient, mock_fhir_client, audit_event_recorder
    ):
        """Exactly ONE AuditEvent MUST be emitted per patient creation operation."""
        initial_count = len(audit_event_recorder)
        patient_id = str(uuid.uuid4())

        audit_payload = _build_audit_event(
            action="C", outcome="0", patient_id=patient_id
        )
        audit_event_recorder.append(audit_payload)

        assert len(audit_event_recorder) == initial_count + 1, (
            "Expected exactly one new AuditEvent per operation"
        )

    @pytest.mark.asyncio
    async def test_audit_events_for_multiple_operations_are_independent(
        self, mock_fhir_client, audit_event_recorder
    ):
        """Each operation MUST produce its own distinct AuditEvent."""
        patient_ids = [str(uuid.uuid4()) for _ in range(3)]

        for pid in patient_ids:
            audit_payload = _build_audit_event(
                action="C", outcome="0", patient_id=pid
            )
            audit_event_recorder.append(audit_payload)

        assert len(audit_event_recorder) >= 3

        # Each event should reference a different patient
        referenced_ids = set()
        for event in audit_event_recorder:
            for entity in event.get("entity", []):
                ref = entity.get("what", {}).get("reference", "")
                referenced_ids.add(ref)

        for pid in patient_ids:
            assert any(pid in ref for ref in referenced_ids), (
                f"Patient {pid} not referenced in any AuditEvent"
            )


